/**
 * Static entry points for JSONC parsing, editing-adjacent utilities and the schema factories. Not instantiable.
 *
 * @example
 * ```ts
 * import { Jsonc } from "@effected/jsonc";
 * import { Effect } from "effect";
 *
 * const program = Effect.gen(function* () {
 *   const value = yield* Jsonc.parse('{ "port": 3000 // dev\n }');
 *   return value; // { port: 3000 }
 * });
 * ```
 *
 * @public
 */

/**
 * Compare two JSONC strings for semantic equality: comments, whitespace, formatting and object key order are ignored; array order is significant. Malformed input is never equal to anything — parse errors on either side yield `false` rather than comparing recovery-parser artifacts. Pure and total.
 */

/**
 * Compare a JSONC string against an existing JavaScript value with the same semantics as {@link Jsonc.equals}: malformed `text` yields `false`. Pure and total.
 */

/**
 * The zero-config `Schema<unknown, string>` — `Jsonc.fromString()` with default options, pre-bound so the common case needs no memoization discipline.
 */

/**
 * Parse JSONC into a plain JavaScript value. Error-recovery parsing: collects every parse error and fails once with the aggregate {@link JsoncParseError}. Returns `unknown`, never `any`.
 */

/**
 * Parse JSONC into an immutable {@link JsoncNode} AST. `Option.none()` for empty input (with `allowEmptyContent`); the aggregate {@link JsoncParseError} for malformed input.
 */

/**
 * Remove all comments from JSONC, producing valid JSON. Pass a `replaceCh` (e.g. `" "`) to replace each comment character instead of deleting it, keeping all offsets stable (line breaks inside block comments are kept). Pure and total.
 */

/**
 * Apply `edits` to `text`, producing a new string. Edits are applied in reverse-offset order so earlier offsets stay valid; the input `edits` array is not mutated. Pure and total.
 */

/**
 * Format `text` and apply the resulting edits in one step (`applyAll ∘ format`). The sole surviving convenience from v3's `formatAndApply`. Pure and total.
 */

/**
 * Find a descendant node by path. String segments navigate object properties; number segments navigate array indices. Returns `Option.none()` when any segment cannot be resolved. Pure.
 */

/**
 * Find the innermost node whose span covers `offset`, or `Option.none()` if the offset is outside this subtree. Pure.
 */

/**
 * Return the JSON path to the innermost node covering `offset`, or `Option.none()` if the offset is outside this subtree. The inverse of {@link JsoncNode.find}. Pure.
 */

/**
 * Reconstruct the plain JavaScript value represented by this subtree. Pure and total — never fails, so no `Effect` wrapper.
 */

